import { Component, OnInit, inject, ChangeDetectorRef } from '@angular/core';
import { CommonModule } from '@angular/common'; // Contient NgFor ou la syntaxe @for

@Component({
  selector: 'app-job-manage',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './job-manage.component.html',
  styleUrls: ['./job-manage.component.css']
})
export class JobManageComponent implements OnInit {
  private cdr = inject(ChangeDetectorRef);

  // Tableau qui va recevoir les vraies annonces du backend
  jobsList: any[] = [];
  isLoading: boolean = true;

  ngOnInit() {
    this.fetchRecruiterJobs();
  }

  fetchRecruiterJobs() {
    const targetUrl = 'http://localhost:3000/api/recruiter/jobs/list';
    const token = localStorage.getItem('token');

    fetch(targetUrl, {
      method: 'GET',
      headers: {
        'Authorization': token ? `Bearer ${token}` : ''
      }
    })
    .then(async res => {
      if (!res.ok) throw new Error("Impossible de récupérer les annonces.");
      return res.json();
    })
    .then(data => {
      // 🌟 On stocke les données reçues (vérifiez si votre backend renvoie directement un tableau ou un objet du type data.jobs)
      this.jobsList = Array.isArray(data) ? data : (data.jobs || []);
      this.isLoading = false;
      this.cdr.detectChanges(); // Force le rendu visuel sur l'interface
    })
    .catch(err => {
      console.error("Erreur récupération jobs:", err);
      this.isLoading = false;
      this.cdr.detectChanges();
    });
  }
}
 <div class="manage-container">
  <div class="manage-card">
    <div class="card-header">
      <h3><i class="bi bi-briefcase-fill"></i> Vos Annonces en Ligne</h3>
      <p>Suivez l'état de diffusion et l'attractivité de vos offres d'emploi actives.</p>
    </div>

    <div class="table-wrapper">
      <table class="jobs-table">
        <thead>
          <tr>
            <th>Intitulé du Poste</th>
            <th>Type de Contrat</th>
            <th>Localisation</th>
            <th>Candidatures Reçues</th>
            <th>Statut</th>
          </tr>
        </thead>
        <tbody>
          <tr>
            <td class="job-title">Développeur Fullstack Angular/Node</td>
            <td>CDI</td>
            <td>Tunis, Tunisie</td>
            <td class="candidate-count"><i class="bi bi-people-fill"></i> 8 profils</td>
            <td><span class="status-badge bg-green">Actif</span></td>
          </tr>
          <tr>
            <td class="job-title">Ingénieur DevOps Cloud</td>
            <td>CDI / SIVP</td>
            <td>Ariana, Tunisie</td>
            <td class="candidate-count"><i class="bi bi-people-fill"></i> 6 profils</td>
            <td><span class="status-badge bg-green">Actif</span></td>
          </tr>
        </tbody>
      </table>
    </div>
  </div>
</div>
